const threshold = 240; // minutos
const stuck_emails = [];

// Obtener el país actual del Loop
const loopItem = $node["Loop1"].json || {};
const country = loopItem.country || "ARG";
const tz = loopItem.timezone || "America/Argentina/Buenos_Aires";

// Obtener "ahora" en UTC y convertir a timezone local
const nowUTC = new Date();
const nowInTz = new Date(nowUTC.toLocaleString('en-US', { timeZone: tz }));
const limitDate = new Date(nowInTz.getTime() - threshold * 60000);

// --- DETECTAR SI WEBMAIL SE EJECUTÓ CORRECTAMENTE ---
// El nodo IMAP (comunidad) cuando falla, retorna el mismo input sin cambios
// Chequeamos si los datos tienen estructura de EMAIL (seq, uid, envelope)
// o estructura de CREDENCIALES (country, user, timezone)

if (items && items.length > 0) {
    const firstItem = items[0];
    const json = firstItem.json || {};

    // Campos que identifica un email válido del IMAP
    const isValidEmail = json.seq !== undefined || json.uid !== undefined || json.envelope !== undefined;

    // Campos que identifica credenciales (input del nodo anterior)
    const isCredentials = (json.country || json.user || json.timezone) && !isValidEmail;

    if (isCredentials) {
        // El IMAP falló: pasó el input sin modificar
        return [{
            json: {
                alerta: true,
                error_type: "webmail",
                error_message: "WebMail falló en la conexión (credenciales o mailbox inválido)",
                country: country,
                cantidad_atascados: 0,
                detalle_atascados: []
            }
        }];
    }

    if (!isValidEmail) {
        // No es email ni credenciales: probablemente output vacío (bandeja vacía)
        // Retornamos un resultado limpio sin error
        return [{
            json: {
                alerta: false,
                cantidad_atascados: 0,
                detalle_atascados: [],
                country: country
            }
        }];
    }
}

// --- PROCESAR EMAILS NORMALMENTE ---
for (const item of items) {
    try {
        const emailData = item.json;
        const envelope = emailData.envelope || {};
        const dateStr = envelope.date;

        if (dateStr) {
            const emailDate = new Date(dateStr);

            if (!isNaN(emailDate.getTime())) {
                const emailInTz = new Date(emailDate.toLocaleString('en-US', { timeZone: tz }));

                if (emailInTz < limitDate) {
                    const diffMs = nowInTz - emailInTz;
                    const minutesStuck = Math.floor(diffMs / (1000 * 60));

                    stuck_emails.push({
                        "received_at": dateStr,
                        "minutes_stuck": minutesStuck,
                        "id": emailData.id,
                        "country": country
                    });
                }
            }
        }
    } catch (e) {
        continue;
    }
}

const outputJson = {
    "alerta": stuck_emails.length > 0,
    "cantidad_atascados": stuck_emails.length,
    "detalle_atascados": stuck_emails,
    "country": country
};

return [{ json: outputJson }];

const THRESHOLD_MINUTES = 240;
const stuckFiles = [];

// Obtener datos del loop de forma segura
const loopItem = $node["Loop1"]?.json || {};
const country = loopItem.country || "ARG";
const tz = loopItem.timezone || "America/Argentina/Buenos_Aires";

const nowUTC = new Date();
const nowInTz = new Date(nowUTC.toLocaleString('en-US', { timeZone: tz }));
const limitDate = new Date(nowInTz.getTime() - THRESHOLD_MINUTES * 60000);

// --- 1. DETECTAR ERROR DEL NODO FTP ---
if (items && items.length > 0) {
  const firstItem = items[0];

  if (firstItem.json?.error) {
    return [{
      json: {
        alerta_ftp: false,
        nodo_error: true,
        error_type: "ftp",
        error_message: firstItem.json.error.message || "FTP error",
        country: country,
        cantidad_archivos: 0,
        detalle_archivos: []
      }
    }];
  }
}

// --- 2. PROCESAR ARCHIVOS NORMALMENTE ---
for (const item of items) {
  try {
    const { modifyTime, name } = item.json;

    if (modifyTime && name) {
      const fileDate = new Date(modifyTime);

      if (!isNaN(fileDate.getTime())) {
        const fileInTz = new Date(fileDate.toLocaleString('en-US', { timeZone: tz }));

        if (fileInTz < limitDate) {
          const diffMs = nowInTz - fileInTz;
          const minsStuck = Math.floor(diffMs / (1000 * 60));

          stuckFiles.push({
            filename: name,
            minutes_stuck: minsStuck,
            country: country
          });
        }
      }
    }
  } catch (error) {
    // Evitamos silenciar el error por completo para poder debuggear en n8n
    console.log(`Error calculando fecha del archivo ${item.json?.name}: ${error.message}`);
  }
}

return [{
  json: {
    alerta_ftp: stuckFiles.length > 0,
    cantidad_archivos: stuckFiles.length,
    detalle_archivos: stuckFiles,
    country: country
  }
}];

// --- CONFIGURACIÓN ---
const MAX_SKIPS = 3; 

// --- 1. OBTENER DATOS DE CONTEXTO (Loop) ---
const loopItem = $node["Loop1"].json; 
const currentContextKey = loopItem.country || 'UNKNOWN';

// --- 2. OBTENER DATOS DE LOS NODOS ANTERIORES ---
const mailData = $('Detect Stuck Emails1').first().json || {};
const ftpData = $('Detect Stuck Files1').first().json || {};

// Accedemos a la memoria global
const staticData = $getWorkflowStaticData('global');
if (!staticData.history) {
    staticData.history = {};
}

// --- 3. RECUPERAR MEMORIA ESPECÍFICA DE ESTE PAÍS ---
const countryMemory = staticData.history[currentContextKey] || { 
    lastSignature: "", 
    skipCount: 0 
};

const memoria_previa = { ...countryMemory };

// --- 4. EXTRAER ESTADO ACTUAL ---
// Revisar si hay error de nodo O atasco
const mailNodeError = mailData.nodo_error === true;
const ftpNodeError = ftpData.nodo_error === true;
const isMailStuck = mailData.alerta === true;
const isFtpStuck = ftpData.alerta_ftp === true;

const isAnyNodeError = mailNodeError || ftpNodeError;

// Generamos las firmas
const mailSig = mailNodeError ? `MAIL_ERROR:${mailData.error_type}` : (isMailStuck ? `MAIL_STUCK:${mailData.cantidad_atascados}` : "");
const ftpSig = ftpNodeError ? `FTP_ERROR:${ftpData.error_type}` : (isFtpStuck ? `FTP_STUCK:${ftpData.cantidad_archivos}` : "");

const currentErrorSignature = `${mailSig}__${ftpSig}`;

// --- 5. LÓGICA DE MEMORIA (Smart Filter Por País) ---
let lastErrorSignature = countryMemory.lastSignature;
let skipCount = countryMemory.skipCount;
let disparar_alerta = false;
let motivo = "";

if (!mailNodeError && !ftpNodeError && !isMailStuck && !isFtpStuck) {
    // CASO A: Todo limpio
    lastErrorSignature = "";
    skipCount = 0;
    disparar_alerta = false;
    motivo = "Sistema OK (Sin errores)";

} else {
    // HAY PROBLEMAS (error de nodo O atasco)
    if (currentErrorSignature !== lastErrorSignature) {
        // CASO B: Problema Nuevo
        disparar_alerta = true;
        skipCount = 0;
        motivo = "Nuevo Problema Detectado";
    } else {
        // CASO C: Mismo Problema
        skipCount++;

        if (skipCount >= MAX_SKIPS) {
            // CASO D: Recordatorio
            disparar_alerta = true;
            skipCount = 0; 
            motivo = `🔔 Recordatorio (Intento ${MAX_SKIPS} alcanzado)`;
        } else {
            // CASO E: Silencio
            disparar_alerta = false;
            motivo = `Silenciado por contador (${skipCount}/${MAX_SKIPS})`;
        }
    }

    lastErrorSignature = currentErrorSignature;
}

// --- 6. GUARDAR EN MEMORIA GLOBAL ---
staticData.history[currentContextKey] = {
    lastSignature: lastErrorSignature,
    skipCount: skipCount
};

// --- 7. CONSTRUCCIÓN DEL MENSAJE (HTML para Teams) ---
let mensaje_teams = "";
const tituloPrincipal = `<h3>Revisión KN (${currentContextKey}): MAIL + FTP</h3>`;

if (disparar_alerta) {
    let titulo = "";
    let cuerpo = [];

    // --- CASO 1: Error en nodo de MAIL ---
    if (mailNodeError) {
        titulo = `⚠️ ERROR WEBMAIL (${currentContextKey})`;
        cuerpo.push(`<strong>Error:</strong> ${mailData.error_message}`);

        // Si además hay archivos atascados en FTP
        if (isFtpStuck) {
            const ftpCount = ftpData.cantidad_archivos || 0;
            cuerpo.push(`<br><em>+ ${ftpCount} archivo(s) atascado(s) en FTP (4+ horas)</em>`);
        }
    }
    // --- CASO 2: Error en nodo de FTP ---
    else if (ftpNodeError) {
        titulo = `⚠️ ERROR FTP (${currentContextKey})`;
        cuerpo.push(`<strong>Error:</strong> ${ftpData.error_message}`);

        // Si además hay emails atascados
        if (isMailStuck) {
            const mailCount = mailData.cantidad_atascados || 0;
            cuerpo.push(`<br><em>+ ${mailCount} correo(s) atascado(s) en INBOX (4+ horas)</em>`);
        }
    }
    // --- CASO 3: Solo atascamientos (sin errores de nodo) ---
    else {
        if (isMailStuck && isFtpStuck) {
            titulo = "⚠️ ALERTA: Problemas en MAIL y FTP";
            const mailCount = mailData.cantidad_atascados || 0;
            const ftpCount = ftpData.cantidad_archivos || 0;
            cuerpo.push(`<strong>MAIL:</strong> ${mailCount} correo(s) atascado(s) (+4h)`);
            cuerpo.push(`<strong>FTP:</strong> ${ftpCount} archivo(s) atascado(s) (+4h)`);
        } else if (isMailStuck) {
            titulo = "📧 ALERTA: Correos en INBOX";
            const mailCount = mailData.cantidad_atascados || 0;
            cuerpo.push(`${mailCount} correo(s) trabado(s) hace +4 horas.`);
        } else if (isFtpStuck) {
            titulo = "📂 ALERTA: Archivos en FTP";
            const ftpCount = ftpData.cantidad_archivos || 0;
            cuerpo.push(`${ftpCount} archivo(s) sin procesar hace +4 horas.`);
        }
    }

    mensaje_teams = `${tituloPrincipal}<br><h2>${titulo}</h2><br>${cuerpo.join('<br>')}<br><br><em>(Estado: ${motivo})</em>`;
}

return [{
    json: {
        pais: currentContextKey,
        enviar_notificacion: disparar_alerta,
        mensaje: mensaje_teams,
        debug_motivo: motivo,
        debug_contador: skipCount,
        debug_memoria_anterior: memoria_previa
    }
}];

